MERGE INTO CONSULTAS FIN USING (SELECT '002844HistorialLaboralAnexos' INFORME ,TO_CLOB(q'[SELECT ROWNUM ITEM, 
           TO_CHAR(CONFIGURACION_ANEXOSHV.DATE_CREATED,'DD/MM/YYYY') FECHADOCUMENTO, 
           NIVEL_AGRUPAMIENTO.NOMBRE DESCRIPCION, 
           CONFIGURACION_ANEXOSHV.FOLIOS,
           SYSDATE FECHAELABORACION,
           NAT_DATOS_PERSONALES.NUMERO_DCTO CEDULA,
           NAT_DATOS_PERSONALES.APELLIDO1 || ' ' || NAT_DATOS_PERSONALES.APELLIDO2 || ' ' || NAT_DATOS_PERSONALES.NOMBRES NOMBRE_FUNCIONARIO
      FROM NIVEL_AGRUPAMIENTO 
INNER JOIN CONFIGURACION_ANEXOSHV 
        ON NIVEL_AGRUPAMIENTO.COMPANIA = CONFIGURACION_ANEXOSHV.COMPANIA                                   
       AND NIVEL_AGRUPAMIENTO.MODULO = CONFIGURACION_ANEXOSHV.MODULO                                  
       AND NIVEL_AGRUPAMIENTO.CODIGO = CONFIGURACION_ANEXOSHV.NIVEL_AGRUPAMIENTO
INNER JOIN NAT_DATOS_PERSONALES
 ON NAT_DATOS_PERSONALES.COMPANIA = CONFIGURACION_ANEXOSHV.COMPANIA
 AND NAT_DATOS_PERSONALES.NUMERO_DCTO = CONFIGURACION_ANEXOSHV.CODIGO
 WHERE NAT_DATOS_PERSONALES.COMPANIA = s$compania$s
 AND NAT_DATOS_PERSONALES.NUMERO_DCTO = s$cedulaEmpleado$s]') CONSULTA, 21 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, 'MPEREZ' CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);